import{_ as t,o as r,c as e,a2 as o}from"./chunks/framework.Bjylvv1V.js";const u=JSON.parse('{"title":"자동이체 관리","description":"","frontmatter":{},"headers":[],"relativePath":"guide/scenarios/auto-transfer.md","filePath":"guide/scenarios/auto-transfer.md","lastUpdated":null}'),l={name:"guide/scenarios/auto-transfer.md"};function s(n,a,i,h,d,c){return r(),e("div",null,[...a[0]||(a[0]=[o(`<h1 id="자동이체-관리" tabindex="-1">자동이체 관리 <a class="header-anchor" href="#자동이체-관리" aria-label="Permalink to &quot;자동이체 관리&quot;">​</a></h1><blockquote><p><strong>소요 시간</strong>: 약 15분 | <strong>난이도</strong>: ★★☆ | <strong>주기</strong>: 매월</p></blockquote><p>은행 자동이체를 통해 관리비를 수납하는 세대를 등록·관리하고, 매월 이체 결과 파일을 수신하여 수납 처리까지 완료하는 프로세스입니다.</p><h2 id="전체-흐름" tabindex="-1">전체 흐름 <a class="header-anchor" href="#전체-흐름" aria-label="Permalink to &quot;전체 흐름&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 자동이체 세대 등록/변경 확인  (3분)  → 신규·해지 세대 정보 업데이트</span></span>
<span class="line"><span>2. 자동이체 출금일 확인          (1분)  → 은행 출금 예정일 확인</span></span>
<span class="line"><span>3. 이체 결과 파일 수신           (2분)  → 은행에서 파일 수신</span></span>
<span class="line"><span>4. 자동이체 수납 처리            (5분)  → 결과 파일로 일괄 수납 처리</span></span>
<span class="line"><span>5. 오류 건 처리                 (3분)  → 이체 실패·이중수납 해소</span></span>
<span class="line"><span>6. 자동납부 신청자 확인          (1분)  → 신청 현황 최종 점검</span></span></code></pre></div><hr><h2 id="사전-준비" tabindex="-1">사전 준비 <a class="header-anchor" href="#사전-준비" aria-label="Permalink to &quot;사전 준비&quot;">​</a></h2><h3 id="자동이체-세대-등록-최초-또는-변경-시" tabindex="-1">자동이체 세대 등록 (최초 또는 변경 시) <a class="header-anchor" href="#자동이체-세대-등록-최초-또는-변경-시" aria-label="Permalink to &quot;자동이체 세대 등록 (최초 또는 변경 시)&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 부과 &gt; <a href="/impo/basic.html">기초정보</a> &gt; 자동이체세대등록 (IMPO1060)</p></blockquote><p>자동이체를 신청한 세대의 계좌 정보를 등록합니다. 신규 신청, 계좌 변경, 해지 시마다 갱신합니다.</p><h3 id="등록-항목" tabindex="-1">등록 항목 <a class="header-anchor" href="#등록-항목" aria-label="Permalink to &quot;등록 항목&quot;">​</a></h3><table tabindex="0"><thead><tr><th>항목</th><th>설명</th></tr></thead><tbody><tr><td>동·호수</td><td>해당 세대</td></tr><tr><td>은행</td><td>출금 은행</td></tr><tr><td>계좌번호</td><td>출금 계좌</td></tr><tr><td>출금일</td><td>매월 자동 출금되는 날짜</td></tr><tr><td>적용 시작일</td><td>자동이체 시작 월</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">세대에서 신청서를 받은 즉시 등록</p><p>자동이체 신청서를 받은 당일에 등록하세요. 누락 시 해당 월 자동이체에서 빠질 수 있습니다.</p></div><hr><h2 id="_1단계-자동이체-세대-등록-변경-확인-3분" tabindex="-1">1단계: 자동이체 세대 등록/변경 확인 (3분) <a class="header-anchor" href="#_1단계-자동이체-세대-등록-변경-확인-3분" aria-label="Permalink to &quot;1단계: 자동이체 세대 등록/변경 확인 (3분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 수납 &gt; <a href="/recp/auto-transfer.html">자동이체수납</a> &gt; 자동납부신청자조회</p></blockquote><p>이번 달 이체 실행 전에 등록 현황을 최종 점검합니다.</p><h3 id="체크리스트" tabindex="-1">체크리스트 <a class="header-anchor" href="#체크리스트" aria-label="Permalink to &quot;체크리스트&quot;">​</a></h3><ul><li>[ ] 이번 달 신규 자동이체 신청 세대가 모두 등록되었는가?</li><li>[ ] 해지 신청 세대의 등록이 삭제 또는 중지 처리되었는가?</li><li>[ ] 계좌 변경 세대의 정보가 갱신되었는가?</li><li>[ ] 이체 출금일이 올바르게 설정되어 있는가?</li></ul><hr><h2 id="_2단계-자동이체-출금일-확인-1분" tabindex="-1">2단계: 자동이체 출금일 확인 (1분) <a class="header-anchor" href="#_2단계-자동이체-출금일-확인-1분" aria-label="Permalink to &quot;2단계: 자동이체 출금일 확인 (1분)&quot;">​</a></h2><p>은행과 협의된 <strong>자동이체 출금일</strong>을 확인합니다. 출금일은 단지마다 다를 수 있으며, 보통 매월 특정 일자(예: 15일, 25일)로 고정됩니다.</p><div class="warning custom-block"><p class="custom-block-title">출금일 전날까지 등록 완료</p><p>출금일 당일 또는 직전에 세대를 등록해도 해당 월 이체에 반영되지 않을 수 있습니다. 은행에서 요구하는 <strong>파일 제출 마감일</strong>을 사전에 확인하세요.</p></div><hr><h2 id="_3단계-이체-결과-파일-수신-2분" tabindex="-1">3단계: 이체 결과 파일 수신 (2분) <a class="header-anchor" href="#_3단계-이체-결과-파일-수신-2분" aria-label="Permalink to &quot;3단계: 이체 결과 파일 수신 (2분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 수납 &gt; <a href="/recp/auto-transfer.html">자동이체수납</a> &gt; 월별자동이체</p></blockquote><p>자동이체 출금 후 은행에서 결과 파일을 수신합니다.</p><h3 id="절차" tabindex="-1">절차 <a class="header-anchor" href="#절차" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>월별자동이체 화면 진입</li><li>해당 연월 선택</li><li><strong>파일 업로드</strong> 또는 <strong>결과 수신</strong> 버튼으로 은행 결과 파일 불러오기</li><li>이체 결과 목록 확인: <ul><li><strong>성공 건</strong>: 정상 출금 완료</li><li><strong>실패 건</strong>: 잔액 부족, 계좌 오류, 출금 정지 등</li></ul></li></ol><div class="tip custom-block"><p class="custom-block-title">은행별 수신 방법 상이</p><p>은행에 따라 결과 파일을 직접 다운로드하거나 시스템 연동으로 자동 수신합니다. 처음 사용 시 은행 담당자에게 절차를 확인하세요.</p></div><hr><h2 id="_4단계-자동이체-수납-처리-5분" tabindex="-1">4단계: 자동이체 수납 처리 (5분) <a class="header-anchor" href="#_4단계-자동이체-수납-처리-5분" aria-label="Permalink to &quot;4단계: 자동이체 수납 처리 (5분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 수납 &gt; <a href="/recp/auto-transfer.html">자동이체수납</a> &gt; 월별자동이체</p></blockquote><p>이체 성공 건을 일괄 수납 처리합니다.</p><h3 id="절차-1" tabindex="-1">절차 <a class="header-anchor" href="#절차-1" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>이체 결과 목록에서 <strong>성공 건</strong> 확인</li><li><strong>일괄 수납처리</strong> 실행</li><li>수납 처리 결과 확인</li></ol><h3 id="기타-수납-처리" tabindex="-1">기타 수납 처리 <a class="header-anchor" href="#기타-수납-처리" aria-label="Permalink to &quot;기타 수납 처리&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 수납 &gt; <a href="/recp/auto-transfer.html">자동이체수납</a> &gt; 월별기타수납</p></blockquote><p>자동이체 외 계좌이체, 현금 등으로 수납된 건을 추가로 처리합니다.</p><hr><h2 id="_5단계-오류-건-처리-3분" tabindex="-1">5단계: 오류 건 처리 (3분) <a class="header-anchor" href="#_5단계-오류-건-처리-3분" aria-label="Permalink to &quot;5단계: 오류 건 처리 (3분)&quot;">​</a></h2><h3 id="이체-실패-건-처리" tabindex="-1">이체 실패 건 처리 <a class="header-anchor" href="#이체-실패-건-처리" aria-label="Permalink to &quot;이체 실패 건 처리&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 수납 &gt; <a href="/recp/process.html">수납처리</a> (RECP1010)</p></blockquote><p>이체 실패 세대는 자동으로 수납 처리가 되지 않으므로 <strong>개별 수납 처리</strong>가 필요합니다.</p><ol><li>이체 실패 목록 확인 (실패 사유 포함)</li><li>세대에 개별 통보 (전화, 문자 등)</li><li>납부 완료 후 수납처리(RECP1010)에서 수동 수납</li></ol><table tabindex="0"><thead><tr><th>실패 사유</th><th>조치</th></tr></thead><tbody><tr><td>잔액 부족</td><td>세대 통보 후 개별 납부 유도</td></tr><tr><td>계좌 오류</td><td>계좌번호 재확인 후 자동이체세대등록 수정</td></tr><tr><td>출금 정지</td><td>세대 통보 및 해지 또는 계좌 변경 안내</td></tr></tbody></table><h3 id="이중수납-확인-및-처리" tabindex="-1">이중수납 확인 및 처리 <a class="header-anchor" href="#이중수납-확인-및-처리" aria-label="Permalink to &quot;이중수납 확인 및 처리&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 수납 &gt; <a href="/recp/auto-transfer.html">자동이체수납</a> &gt; 월별이중수납</p></blockquote><p>동일 세대에서 자동이체와 다른 방법으로 중복 납부된 건을 확인하고 처리합니다.</p><ol><li>월별이중수납 화면에서 이중수납 세대 조회</li><li>이중 출금 여부 확인</li><li>환불 또는 다음 달 차감 처리</li></ol><div class="danger custom-block"><p class="custom-block-title">이중수납 즉시 처리</p><p>이중수납을 방치하면 세대 민원으로 이어집니다. 발견 즉시 해당 세대에 통보하고 환불 또는 차월 차감 방법을 협의하세요.</p></div><hr><h2 id="_6단계-자동납부-신청자-확인-1분" tabindex="-1">6단계: 자동납부 신청자 확인 (1분) <a class="header-anchor" href="#_6단계-자동납부-신청자-확인-1분" aria-label="Permalink to &quot;6단계: 자동납부 신청자 확인 (1분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 수납 &gt; <a href="/recp/auto-transfer.html">자동이체수납</a> &gt; 자동납부신청자조회</p></blockquote><p>이번 달 처리 결과를 기준으로 자동납부 신청 현황을 최종 확인합니다.</p><h3 id="확인-포인트" tabindex="-1">확인 포인트 <a class="header-anchor" href="#확인-포인트" aria-label="Permalink to &quot;확인 포인트&quot;">​</a></h3><ul><li>[ ] 자동납부 신청 세대 수가 예상과 일치하는가?</li><li>[ ] 이번 달 신규 등록 세대가 정상 반영되었는가?</li><li>[ ] 해지 세대가 목록에서 제외되었는가?</li></ul><hr><h2 id="자주-발생하는-문제" tabindex="-1">자주 발생하는 문제 <a class="header-anchor" href="#자주-발생하는-문제" aria-label="Permalink to &quot;자주 발생하는 문제&quot;">​</a></h2><h3 id="특정-세대가-자동이체-목록에-없어요" tabindex="-1">특정 세대가 자동이체 목록에 없어요 <a class="header-anchor" href="#특정-세대가-자동이체-목록에-없어요" aria-label="Permalink to &quot;특정 세대가 자동이체 목록에 없어요&quot;">​</a></h3><p><strong>원인</strong>: 자동이체세대등록(IMPO1060)에 해당 세대가 등록되지 않았거나, 적용 시작일이 이번 달 이후로 설정된 경우입니다. <strong>해결</strong>: 자동이체세대등록 화면에서 해당 세대를 검색하여 등록 여부와 적용 시작일을 확인하세요.</p><h3 id="이체-결과-파일이-안-올라가요" tabindex="-1">이체 결과 파일이 안 올라가요 <a class="header-anchor" href="#이체-결과-파일이-안-올라가요" aria-label="Permalink to &quot;이체 결과 파일이 안 올라가요&quot;">​</a></h3><p><strong>원인</strong>: 파일 형식이 맞지 않거나, 은행에서 지정한 파일 형식과 다른 경우입니다. <strong>해결</strong>: 은행에서 제공한 파일의 형식(확장자, 인코딩)을 확인하고, 시스템에서 지원하는 형식과 맞는지 비교하세요. 담당자에게 문의가 필요할 수 있습니다.</p><h3 id="이체-성공인데-수납이-안-되어-있어요" tabindex="-1">이체 성공인데 수납이 안 되어 있어요 <a class="header-anchor" href="#이체-성공인데-수납이-안-되어-있어요" aria-label="Permalink to &quot;이체 성공인데 수납이 안 되어 있어요&quot;">​</a></h3><p><strong>원인</strong>: 일괄 수납처리를 실행하지 않은 경우입니다. <strong>해결</strong>: 월별자동이체 화면에서 결과 파일 확인 후 <strong>일괄 수납처리</strong> 버튼을 클릭하세요. 파일 수신과 수납 처리는 별개 단계입니다.</p><h3 id="이중수납이-발생했어요" tabindex="-1">이중수납이 발생했어요 <a class="header-anchor" href="#이중수납이-발생했어요" aria-label="Permalink to &quot;이중수납이 발생했어요&quot;">​</a></h3><p><strong>원인</strong>: 세대에서 자동이체 출금 전에 창구·앱 등으로 이미 납부한 경우입니다. <strong>해결</strong>: 월별이중수납 화면에서 해당 건을 확인하고, 세대와 협의하여 환불 또는 다음 달 차감으로 처리하세요.</p><hr><h2 id="관련-메뉴" tabindex="-1">관련 메뉴 <a class="header-anchor" href="#관련-메뉴" aria-label="Permalink to &quot;관련 메뉴&quot;">​</a></h2><ul><li><a href="/impo/basic.html">자동이체세대등록</a> - 자동이체 세대 정보 관리 (IMPO1060)</li><li><a href="/recp/auto-transfer.html">월별자동이체</a> - 이체 결과 수신 및 수납 처리</li><li><a href="/recp/auto-transfer.html">월별기타수납</a> - 자동이체 외 수납 처리</li><li><a href="/recp/auto-transfer.html">월별이중수납</a> - 이중 수납 확인 및 처리</li><li><a href="/recp/auto-transfer.html">자동납부신청자조회</a> - 자동납부 현황 조회</li><li><a href="/recp/process.html">수납처리</a> - 이체 실패 건 수동 수납 (RECP1010)</li></ul>`,70)])])}const b=t(l,[["render",s]]);export{u as __pageData,b as default};
